#!/usr/bin/env bash
# general-playbook.sh — 通用 Playbook 决策助手 for 加密链上交易.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="加密链上交易"
TOPIC="通用 Playbook"

usage() {
  cat <<EOF
general-playbook.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 5 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./general-playbook.sh             # interactive
  ./general-playbook.sh --dry-run   # walk through but no file
  ./general-playbook.sh --json      # JSON to stdout
  ./general-playbook.sh --explain   # show backing playbook rules + mental models
  ./general-playbook.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 通用 Playbook 主题下的 playbook 规则组合成交互树。

基于 5 条规则:
  • 如果 要建任何仓位 → 则 先写下「能承受的最大损失（1R）+ 在哪证明自己错了（失效条件）+ 仓位大小」，缺失效定义就不点确认。案例：Crypto
  • 如果 只看到单一读数 → 则 （TVL / 聪明钱标签 / 份额 / ROI / 资金费率），则挂日期 + 第二源交叉，绝不信单一 vendor 标称
  • 如果 某 KOL 或聪明钱地址给信号 → 则 先查其持仓/基金/返佣/项目关系，按利益方向打折，当「有立场的倡导」而非中立。案例：Delphi 在 LUNA 重仓期间
  • 如果 钱包要交互新合约或打新 → 则 用隔离热钱包（只放可完全承受归零的额）+ 事后 revoke 授权，主仓永远在冷钱包。案例：Bybit 14 亿美元盲签
  • 如果 要上杠杆 → 则 默认不用；要用也只为对冲降风险而非放大，永续先看资金费率与清算热图再定方向。案例：Cobie「I use leverag

相关心智模型:
  • 流动性是母潮，价格是浪（先读流动性，再读叙事）: 加密资产长期是「全球美元流动性的温度计」——价格的大方向由央行/财政释放的流动性母潮决定，单个币的叙事只是骑在母潮上的浪；资深人先判断「现在流动性在扩张还是收缩」，再谈选币。
  • 先定能亏多少，再谈能赚多少（仓位/风控 > 入场与预测）: 交易的 edge 不在「预测对方向」，而在「每笔先定义 1R 风险（在哪证明自己错）+ 用 R 倍数记录复盘」——把每笔交易当一次概率抽样，活下来的人靠期望值而非单次暴击赚钱。

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "要建任何仓位"
  "只看到单一读数"
  "某 KOL 或聪明钱地址给信号"
  "钱包要交互新合约或打新"
  "要上杠杆"
)
declare -a RULE_ACTIONS=(
  "先写下「能承受的最大损失（1R）+ 在哪证明自己错了（失效条件）+ 仓位大小」，缺失效定义就不点确认。案例：CryptoCred 教学——每个交易想法都要明确「这个位为什么重要、什么会让它失效、如何管理仓位」(evidence: [T01-S041])"
  "（TVL / 聪明钱标签 / 份额 / ROI / 资金费率），则挂日期 + 第二源交叉，绝不信单一 vendor 标称。案例：Nansen 标签与 DefiLlama TVL 都需 caveat，口径随报告波动 (evidence: [T02-S004])"
  "先查其持仓/基金/返佣/项目关系，按利益方向打折，当「有立场的倡导」而非中立。案例：Delphi 在 LUNA 重仓期间连发看多研报，是研报利益冲突的经典教训 (evidence: [T04-S009])"
  "用隔离热钱包（只放可完全承受归零的额）+ 事后 revoke 授权，主仓永远在冷钱包。案例：Bybit 14 亿美元盲签被盗事件推动 Clear Signing 成标准 (evidence: [T02-S019])"
  "默认不用；要用也只为对冲降风险而非放大，永续先看资金费率与清算热图再定方向。案例：Cobie「I use leverage close to never and typically to reduce risk」，把高杠杆当出局风险而非赚钱工具 (evidence: [T01-S023])"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "general-playbook-decision"
fi
